'use strict'

const {
  ok,
  same: deepEqual,
  strictSame: strictEqual,
  notSame: notStrictEqual,
  test: tapTest
} = require('tap')

const test = function () {
  if (typeof arguments[2] === 'function') {
    tapTest(arguments[0], arguments[1], t => {
      arguments[2](t)
      t.end()
    })
  } else {
    tapTest(arguments[0], t => {
      arguments[1](t)
      t.end()
    })
  }
}

